import java.util.ArrayList;
import java.util.HashMap;

import javax.persistence.Column;
import javax.persistence.Entity;
import javax.persistence.GeneratedValue;
import javax.persistence.Id;

@Entity
public class User {

    // the primary key (ID) is auto generated by ObjectDB
    @Id 
    @GeneratedValue 
    private Integer id = null;
    
    private String firstName;
    private String lastName;

    @Column(unique=true)
    private String email = "";

    private String token = null;

    private float[] embeddings;

    private ArrayList<String> interests;
    private ArrayList<User> followedUsers;
    private ArrayList<Club> registeredClubs;
    private HashMap<Integer, Integer> clubPrivileges;
    private int privileges = Privileges.NORMAL_USER;

    // a no argument constructor is required by JPA
    public User() {
    }

    public User(String firstName, String lastName, String email) {
        this.firstName = firstName.trim();
        this.lastName = lastName.trim();
        this.email = email.trim();
    }

    // Getters and Setters
    public Integer getId() {
        return id;
    }

    public String getFirstName() {
        return firstName;
    }

    public String getLastName() {
        return lastName;
    }

    public String getFullName() {
        return firstName + " " + lastName;
    }

    public String getEmail() {
        return email;
    }

    public void setFirstName(String firstName) {
        this.firstName = firstName.trim();
    }

    public void setLastName(String lastName) {
        this.lastName = lastName.trim();
    }

    public void setEmail(String email) {
        if (!this.email.equals("")) return;
        // for now we can't support changing the email address because it introduces additional complexity
        this.email = email.trim();
    }

    public void followUser(User user) {
        followedUsers.add(user);
    }

    public void unfollowUser(User user) {
        followedUsers.remove(user);
    }

    public void joinClub(Club club) {
        registeredClubs.add(club);
        setClubPrivilege(club, Privileges.NORMAL_USER);
    }

    public void setClubPrivilege(Club club, int privilege) {
        // note that the privilege flag here is a composite flag created by using bitwise OR
        // unless the user is getting banned, then the flag is just 0
        clubPrivileges.put(club.getId(), privilege);
    }

    public void leaveClub(Club club) {
        registeredClubs.remove(club);
        clubPrivileges.remove(club.getId());
    }

    public boolean isAdmin() {
        return (privileges & Privileges.ADMIN) != 0;
    }

    public boolean hasClubPrivilege(Club club, int privilegeType) {
        // note that the privilegeType flag here is NOT a composite flag
        int currentPrivilege = clubPrivileges.get(club.getId());
        if (currentPrivilege <= Privileges.NORMAL_USER) return false;
        return ((currentPrivilege & privilegeType) != 0);
    }

    public void addInterest(String interest) {
        interests.add(interest);
    }

    public void removeInterest(String interest) {
        interests.remove(interest);
    }

    public void setInterests(ArrayList<String> interests) {
        this.interests = interests;
    }

    public void banUser() {
        for (int i = 0; i < embeddings.length; i++) {
            embeddings[i] = 0;
        }
        followedUsers.clear();
        registeredClubs.clear();
        token = null;
        privileges = Privileges.BANNED_USER;
    }

    public boolean isBanned() {
        return (privileges == Privileges.BANNED_USER);
    }

    public void banFromClub(Club club) {
        setClubPrivilege(club, Privileges.BANNED_USER);
    }

    public boolean isBannedFromClub(Club club){
        return clubPrivileges.get(club.getId()) == Privileges.BANNED_USER;
    }

    public String getToken() {
        return token;
    }

    public void generateToken() {
        token = SecureTokenGenerator.generate();
    }

    public boolean validateToken(String providedToken) {
        // FIXME: there is a timing vulnerability to fix here, we should use constant time comparison
        if (token == null ||providedToken == null) return false;
        Long storedTTL = Long.parseLong(token.substring(1 + token.lastIndexOf(':')));
        if (System.currentTimeMillis() > storedTTL) return false;
        return providedToken.equals(token);
    }

    @Override
    public String toString() {
        return "User {id=" + id + ", name='" + getFullName() + "', email='" + email + "'}";
    }
}